export const DEFAULT_EMBEDDED_FONT_DECODE_POLICY = {
    allowRestrictedRendering: false,
    maxInputBytes: 64 * 1024 * 1024,
    maxOutputBytes: 64 * 1024 * 1024,
};
export function embeddedFontFaceType(type) {
    switch (type) {
        case 1:
            return "regular";
        case 2:
            return "bold";
        case 3:
            return "italic";
        case 4:
            return "boldItalic";
        default:
            return "unknown";
    }
}
